function createDialogMap(
  language: string,
  row: string,
): Record<ContentEditorDialogSource, string> {
  const translations = row.split("|");
  if (translations.length !== CONTENT_EDITOR_DIALOG_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} content editor dialog translations must have ${CONTENT_EDITOR_DIALOG_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    CONTENT_EDITOR_DIALOG_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<ContentEditorDialogSource, string>;
}

const CONTENT_EDITOR_DIALOG_SOURCE_TRANSLATIONS = Object.fromEntries(
  Object.entries(DIALOG_ROWS).map(([language, row]) => [
    language,
    createDialogMap(language, row),
  ]),
) as Record<LocalizedLanguage, Record<ContentEditorDialogSource, string>>;

export const CONTENT_EDITOR_ADDITIONAL_SOURCE_TRANSLATIONS = (
  Object.keys(ROWS) as LocalizedLanguage[]
).reduce(
  (translations, language) => {
    translations[language] = {
      ...(CONTENT_EDITOR_MANUAL_ADDITIONAL_SOURCE_TRANSLATIONS[language] ?? {}),
      ...CONTENT_EDITOR_DIALOG_SOURCE_TRANSLATIONS[language],
    };
    return translations;
  },
  {} as Record<LocalizedLanguage, Record<string, string>>,
);
